CREATE DATABASE IF NOT EXISTS cryptoradar CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE cryptoradar;
CREATE TABLE users (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(120) NOT NULL, email VARCHAR(180) NOT NULL UNIQUE, password_hash VARCHAR(255) NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE favorite_coins (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT NOT NULL, coin_id VARCHAR(120) NOT NULL, coin_name VARCHAR(120) NOT NULL, symbol VARCHAR(30) NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uniq_fav (user_id, coin_id), FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE portfolio_transactions (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT NOT NULL, coin_id VARCHAR(120) NOT NULL, coin_name VARCHAR(120) NOT NULL, symbol VARCHAR(30) NOT NULL, amount_invested DECIMAL(20,8) NOT NULL, coin_price DECIMAL(20,8) NOT NULL, quantity DECIMAL(28,12) NOT NULL, purchased_at DATETIME NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE price_alerts (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT NOT NULL, coin_id VARCHAR(120) NOT NULL, coin_name VARCHAR(120) NOT NULL, symbol VARCHAR(30) NOT NULL, target_price DECIMAL(20,8) NOT NULL, currency ENUM('USD','BRL') DEFAULT 'USD', direction ENUM('above','below') NOT NULL, status ENUM('active','triggered','paused') DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE chat_history (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT NOT NULL, question TEXT NOT NULL, answer TEXT NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE search_history (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT NULL, query VARCHAR(255) NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL);